const ALLOWED = [
  'order_index','scheduled_date','name','asset_url','thumbnail_url',
  'caption','caption_alt','caption_alt_platform','post_url','cta','tweaks','status','linear_issue_id',
  'kasper_approved_at','posted_at','platform','platforms','color',
  'video_status','graphic_status','caption_status',
  'graphic_linear_issue_id',
  'video_tweaks','graphic_tweaks','caption_tweaks',
  'client_video_approved_at','client_graphic_approved_at','client_caption_approved_at'
];
const body = ($input.first() && $input.first().json && $input.first().json.body) || {};
const client = String(body.client || '').trim();
if (!client) throw new Error('client required');
const post = body.post || {};
let id = String(post.id || '').trim();
if (!id) {
  id = 'p_' + Date.now().toString(36) + '_' + Math.random().toString(36).slice(2,8);
}
const row = { id, updated_at: new Date().toISOString() };
for (const k of ALLOWED) {
  if (Object.prototype.hasOwnProperty.call(post, k)) {
    const v = post[k];
    row[k] = v == null ? '' : String(v);
  }
}
return [{ json: { ...row, _sheetName: 'Calendar_' + client, _client: client } }];

// Duplicate-link guard: an import double-fire used to append two rows for
// the same Linear issue. The FE collapses cards sharing a linear_issue_id to
// one visible card, so archiving one twin leaves the other live and the card
// 'comes back' on refresh. Make append idempotent on linear_issue_id: if a
// non-archived row already owns the incoming link, return THAT row instead of
// appending a second one. Blank-link posts (manual cards) always append.
const incoming = $('Build Row From Post').first().json;
const twins = $input.all().map(t => (t && t.json) || {});
const link = String(incoming.linear_issue_id || '').trim();
let dupe = null;
if (link) {
  dupe = twins.find(t => t && t.id
    && String(t.id) !== String(incoming.id)
    && String(t.status || '').toLowerCase() !== 'archived'
    && String(t.linear_issue_id || '').trim() === link) || null;
}
if (dupe) {
  return [{ json: Object.assign({}, dupe, { _dupe: true }) }];
}
return [{ json: Object.assign({}, incoming, { _dupe: false }) }];

const j = ($input.first() && $input.first().json) || {};
const out = {};
for (const k of Object.keys(j)) { if (k.charAt(0) === '_') continue; out[k] = j[k]; }
return [{ json: { ok: true, deduped: true, post: out } }];

const j = $input.item.json;
const out = {};
for (const k of Object.keys(j)) {
  if (k.charAt(0) === '_') continue;
  out[k] = j[k];
}
return { json: out };
